const body = $json.body;

// Check if photo exists
if (!body.photo) {
  // No photo - pass through
  return [{ json: body }];
}

// Photo exists - prepare for upload
const photoBase64 = body.photo;
const originalFilename = body.photoFilename || 'photo.jpg';

// Clean filename
const fileExtension = originalFilename.split('.').pop().toLowerCase();
const timestamp = Date.now();
const randomStr = Math.random().toString(36).substring(2, 8);
const cleanFilename = `${timestamp}_${randomStr}.${fileExtension}`;

// Convert base64 to binary
const binaryData = Buffer.from(photoBase64, 'base64');

// Determine MIME type
let mimeType = 'image/jpeg';
if (fileExtension === 'png') mimeType = 'image/png';
if (fileExtension === 'webp') mimeType = 'image/webp';

return [{
  json: {
    ...body,
    photoFilename: cleanFilename,
    hasPhoto: true
  },
  binary: {
    photo: {
      data: binaryData.toString('base64'),
      mimeType: mimeType,
      fileName: cleanFilename
    }
  }
}];

const body = $json;

// Only attempt OG download if there's an ogImageUrl and no manual photo
if (body.ogImageUrl && body.ogImageUrl.startsWith('http')) {
  return [{ json: { ...body, hasOGImage: true } }];
}

// No OG image — pass through
return [{ json: { ...body, hasOGImage: false } }];

// Get original body from Check OG Image node
const body = $('Check OG Image').first().json;

// Generate a clean filename for storage
const timestamp = Date.now();
const randomStr = Math.random().toString(36).substring(2, 8);
const cleanFilename = `og_${timestamp}_${randomStr}.jpg`;

// Get the binary data downloaded from OG URL
const binaryData = $binary.data;

return [{
  json: {
    ...body,
    photoFilename: cleanFilename,
    hasPhoto: true,
    photoSource: 'og',
    ogImageUrl: null
  },
  binary: {
    photo: {
      data: binaryData.data,
      mimeType: binaryData.mimeType || 'image/jpeg',
      fileName: cleanFilename
    }
  }
}];

